import{_ as e,H as a,f as l,i as r}from"./chunks/framework.eFU6Tutu.js";const f=JSON.parse('{"title":"Перец (сладкий и острый)","description":"","frontmatter":{},"headers":[],"relativePath":"plants/peppers.md","filePath":"plants/peppers.md"}'),n={name:"plants/peppers.md"};function s(i,t,o,d,h,p){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="перец-сладкии-и-острыи" tabindex="-1">Перец (сладкий и острый) <a class="header-anchor" href="#перец-сладкии-и-острыи" aria-label="Permalink to &quot;Перец (сладкий и острый)&quot;">​</a></h1><p>Выращивание перца на подоконнике — занятие не только полезное, но и очень декоративное. Компактные кустики, усыпанные яркими плодами, станут настоящим украшением интерьера, а заодно обеспечат вас свежей, ароматной приправой или витаминным овощем круглый год.</p><h2 id="описание" tabindex="-1">Описание <a class="header-anchor" href="#описание" aria-label="Permalink to &quot;Описание&quot;">​</a></h2><p>Перец — многолетнее растение, которое при хорошем уходе может жить и плодоносить в комнате 2-3 года. Стебель со временем становится древовидным. Листья одиночные, зелёные. Цветки белые или фиолетовые. Плоды — ложные ягоды, разнообразной формы и окраски.</p><h2 id="популярные-сорта-для-дома" tabindex="-1">Популярные сорта для дома <a class="header-anchor" href="#популярные-сорта-для-дома" aria-label="Permalink to &quot;Популярные сорта для дома&quot;">​</a></h2><p>Для подоконника выбирайте компактные, самоопыляемые, раннеспелые сорта и гибриды. <strong>Важно:</strong> Не сажайте сладкие и острые перцы рядом — они переопыляются, и сладкие перцы станут горькими.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Сорт</th><th style="text-align:left;">Тип</th><th style="text-align:left;">Характеристика</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Сладкий перец «Балконное чудо»</strong></td><td style="text-align:left;">Сладкий</td><td style="text-align:left;">Ранний, высота до 50 см, плоды красные, массой до 80 г</td></tr><tr><td style="text-align:left;"><strong>Сладкий перец «Красный колокольчик»</strong></td><td style="text-align:left;">Сладкий</td><td style="text-align:left;">Карликовый сорт (30-40 см), плоды мелкие, очень сладкие</td></tr><tr><td style="text-align:left;"><strong>Сладкий перец «Пикколо»</strong></td><td style="text-align:left;">Сладкий</td><td style="text-align:left;">Очень компактный (25-30 см), плоды мелкие (2-3 см), отлично подходит для окон</td></tr><tr><td style="text-align:left;"><strong>Острый перец «Медуза»</strong></td><td style="text-align:left;">Острый</td><td style="text-align:left;">Очень декоративный куст высотой 25-30 см. Плоды длинные, свисающие, практически не острые</td></tr><tr><td style="text-align:left;"><strong>Острый перец «Огонёк»</strong></td><td style="text-align:left;">Острый</td><td style="text-align:left;">Классический комнатный перец. Высота 30-45 см, плоды красные, жгучие</td></tr><tr><td style="text-align:left;"><strong>Острый перец «Чили» (карликовый)</strong></td><td style="text-align:left;">Острый</td><td style="text-align:left;">Многочисленные мелкие плоды-горошины, очень декоративно</td></tr></tbody></table><h2 id="уход" tabindex="-1">Уход <a class="header-anchor" href="#уход" aria-label="Permalink to &quot;Уход&quot;">​</a></h2><p>Подробное руководство по выращиванию, пересадке и формировке сладкого и острого перца на подоконнике читайте в <a href="/care/peppers.html">гайде по уходу за перцами</a>.</p><h2 id="как-использовать-в-еде" tabindex="-1">Как использовать в еде <a class="header-anchor" href="#как-использовать-в-еде" aria-label="Permalink to &quot;Как использовать в еде&quot;">​</a></h2><p><a href="/recipes/peppers.html">Рецепты с перцами</a></p><ul><li><strong>Сладкий:</strong> Свежие салаты, лечо, фаршированные перцы</li><li><strong>Острый:</strong> Как приправа к супам, мясу, в маринады и соусы</li></ul><h2 id="полезные-своиства" tabindex="-1">Полезные свойства <a class="header-anchor" href="#полезные-своиства" aria-label="Permalink to &quot;Полезные свойства&quot;">​</a></h2><ul><li><strong>Сладкий перец:</strong> рекордсмен по содержанию витамина С. Также богат витамином А и калием.</li><li><strong>Острый перец:</strong> содержит капсаицин, стимулирует аппетит и обмен веществ, обладает антибактериальными свойствами.</li></ul><h2 id="источники-информации" tabindex="-1">Источники информации <a class="header-anchor" href="#источники-информации" aria-label="Permalink to &quot;Источники информации&quot;">​</a></h2><ul><li><a href="https://azbyka.ru/garden/vyrashhivanie-perczev-v-kvartire/" target="_blank" rel="noreferrer">Азбука садовода — Выращивание перцев в квартире</a></li><li><a href="https://7dach.ru/OrganicMix/perec-na-podokonnike-master-klass-po-vyraschivaniyu-i-uhodu-281486.html" target="_blank" rel="noreferrer">7 дач — Перец на подоконнике: мастер-класс</a></li></ul><h2 id="похожие-растения" tabindex="-1">Похожие растения <a class="header-anchor" href="#похожие-растения" aria-label="Permalink to &quot;Похожие растения&quot;">​</a></h2><ul><li><a href="/plants/tomatoes.html">Помидоры (черри)</a></li><li><a href="/plants/radish.html">Редис</a></li></ul>',18)])])}const c=e(n,[["render",s]]);export{f as __pageData,c as default};
